def add_all(*args):
    total = 0
    for n in args:
        total += n
    return total

print(add_all(1, 2, 3))

def show_profile(**kwargs):
    for key, value in kwargs.items():
        print(f"{key}: {value}")

show_profile(name="Alice", city="London")

def order(place, *dishes, tip=0, **extras):
    print(place, dishes, tip, extras)

order("Cafe", "Pizza", "Salad", tip=10, seat="window")
